/* ====================================================================
 * JSON 安全解析辅助函数
 * 替代 atoi/atof，提供输入验证和错误回报
 * ==================================================================== */

/**
 * @brief 安全字符串转整数（替代 atoi）
 * @param str 输入字符串
 * @param default_val 解析失败时的默认值
 * @param error 输出参数：0=成功，非0=解析失败
 * @return 解析后的整数值
 */
static int json_get_int_safe(const char* str, int default_val, int* error) {
    if (!str || !str[0]) {
        if (error) *error = 1;
        return default_val;
    }
    char* endptr = NULL;
    long val = strtol(str, &endptr, 10);
    if (endptr == str || *endptr != '\0') {
        if (error) *error = 1;
        return default_val;
    }
    if (val > INT_MAX) val = INT_MAX;
    if (val < INT_MIN) val = INT_MIN;
    if (error) *error = 0;
    return (int)val;
}

/**
 * @brief 安全字符串转浮点数（替代 atof）
 * @param str 输入字符串
 * @param default_val 解析失败时的默认值
 * @param error 输出参数：0=成功，非0=解析失败
 * @return 解析后的浮点数值
 */
static float json_get_float_safe(const char* str, float default_val, int* error) {
    if (!str || !str[0]) {
        if (error) *error = 1;
        return default_val;
    }
    char* endptr = NULL;
    float val = strtof(str, &endptr);
    if (endptr == str || *endptr != '\0') {
        if (error) *error = 1;
        return default_val;
    }
    if (error) *error = 0;
    return val;
}

