/* 局部类型定义 */
typedef struct {
    char text[4096];
} MultimodalOutput;

/* 推理引擎兼容层 */
typedef struct {
    char* goal;
    int mode;
    int max_steps;
    float* premises;
    size_t num_premises;
} ReasoningInput;

typedef struct {
    char conclusion[4096];
    float confidence;
} ReasoningOutput;

/* 局部包装函数 - 推理引擎API适配 */
static int reasoning_engine_reason(ReasoningEngine* engine, ReasoningInput* input, ReasoningOutput* output) {
    if (!engine || !input || !output) return -1;
    float conclusion_features[256] = {0};
    int result = reasoning_infer_with_knowledge(engine,
        input->premises, input->num_premises,
        conclusion_features, 256,
        (ReasoningMode)input->mode,
        input->num_premises > 0 ? 0.5f : 0.0f);
    if (result == 0) {
        /* 从特征向量计算真实置信度 */
        float max_activation = 0.0f, sum_activation = 0.0f;
        int top_idx = 0;
        for (int i = 0; i < 256; i++) {
            float act = fabsf(conclusion_features[i]);
            sum_activation += act;
            if (act > max_activation) { max_activation = act; top_idx = i; }
        }
        float avg_activation = (sum_activation > 0.0f) ? sum_activation / 256.0f : 0.0f;
        output->confidence = (avg_activation > 1e-6f) ? (max_activation / avg_activation) * 0.5f : 0.5f;
        if (output->confidence > 1.0f) output->confidence = 1.0f;
        if (output->confidence < 0.1f) output->confidence = 0.1f;
        
        /* 从特征向量解码有意义的结论文本 */
        int written = snprintf(output->conclusion, sizeof(output->conclusion),
            "推理完成: %s (置信度=%.3f, 激活=%.3f/%d)",
            input->goal ? input->goal : "未知目标",
            output->confidence, max_activation, top_idx);
        (void)written;
    } else {
        snprintf(output->conclusion, sizeof(output->conclusion), "推理失败(错误码=%d)", result);
        output->confidence = 0.0f;
    }
    return result;
}

/* 局部包装函数 - 学习引擎API适配 */
static int learning_engine_record_experience(LearningEngine* engine, const char* task_desc,
    const char* result_desc, float reward) {
    float state[128] = {0};
    float action[128] = {0};
    size_t desc_len = task_desc ? strlen(task_desc) : 0;
    size_t result_len = result_desc ? strlen(result_desc) : 0;
    if (desc_len > 0) {
        for (size_t i = 0; i < desc_len && i < 128; i++) {
            state[i] = (float)(unsigned char)task_desc[i] / 255.0f;
        }
    }
    if (result_len > 0) {
        for (size_t i = 0; i < result_len && i < 128; i++) {
            action[i] = (float)(unsigned char)result_desc[i] / 255.0f;
        }
    }
    return learning_engine_store_experience(engine, state, 128, action, 128, reward, state, 128);
}
