static int handle_api_post_voice_recognize(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    /* P21修复: 真实调用语音识别引擎而非返回硬编码假数据 */
    void* sr = selflnn_get_speech_recognizer();
    if (!sr) {
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256,
                "{\"text\":\"语音识别模块未初始化，请连接麦克风或启动多模态管理器\",\"command\":null}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 503;
        }
        return 0;
    }
    /* 尝试从请求中提取音频数据并调用真实语音识别 */
    if (request_data && request_length > 0) {
        SpeechRecognitionResult sr_result;
        int ret;
        memset(&sr_result, 0, sizeof(sr_result));
        ret = speech_recognizer_recognize((SpeechRecognizer*)sr, 
            (const float*)request_data, (int)(request_length / sizeof(float)), &sr_result);
        if (ret == 0 && sr_result.text && sr_result.text[0]) {
            size_t len = strlen(sr_result.text);
            json_data = (char*)safe_malloc(len + 256);
            if (json_data) {
                snprintf(json_data, len + 256,
                    "{\"text\":\"%s\",\"confidence\":%.3f,\"command\":null,\"status\":\"ok\"}",
                    sr_result.text, sr_result.confidence);
                response->data = json_data;
                response->data_length = strlen(json_data);
                response->status_code = 200;
                if (sr_result.token_confidences) safe_free((void**)&sr_result.token_confidences);
                if (sr_result.token_boundaries) safe_free((void**)&sr_result.token_boundaries);
                if (sr_result.token_ids) safe_free((void**)&sr_result.token_ids);
                if (sr_result.text) safe_free((void**)&sr_result.text);
                return 0;
            }
        }
        if (sr_result.text) safe_free((void**)&sr_result.text);
    }
    /* 无有效音频数据时返回空结果而非假数据 */
    json_data = (char*)safe_malloc(256);
    if (json_data) {
        snprintf(json_data, 256,
            "{\"text\":\"（未检测到有效语音信号）\",\"command\":null,\"status\":\"empty\"}");
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
    return 0;
}
static int handle_api_post_voice_synthesize(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    size_t hex_len = 0;

/* 同步TTS修复 —— 连接到真实TTS引擎 */
    if (!server->multimodal_manager) {
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256, "{\"audio\":null,\"error\":\"TTS模块未初始化\",\"status\":\"unavailable\"}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 503;
        }
        return 0;
    }

    if (!server->tts_engine) {
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256, "{\"audio\":null,\"error\":\"TTS引擎未初始化\",\"status\":\"unavailable\"}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 503;
        }
        return 0;
    }

    char tts_text[4096] = {0};
    if (request_data && request_length > 0) {
        parse_json_string(request_data, "text", tts_text, sizeof(tts_text));
    }
    if (strlen(tts_text) == 0) {
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256, "{\"audio\":null,\"error\":\"文本内容为空\",\"status\":\"error\"}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 400;
        }
        return 0;
    }

    /* SEH保护TTS合成调用 —— 访问违例不会导致服务器崩溃 */
    TTSAudio* audio = NULL;
#ifdef _MSC_VER
    __try {
        audio = tts_synthesize(server->tts_engine, tts_text);
    } __except(EXCEPTION_EXECUTE_HANDLER) {
        audio = NULL;
    }
#else
    audio = tts_synthesize(server->tts_engine, tts_text);
#endif
    if (!audio || !audio->samples || audio->num_samples <= 0) {
        tts_audio_free(audio);
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256,
                "{\"audio\":null,\"error\":\"TTS合成失败\",\"status\":\"error\"}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 500;
        }
        return 0;
    }

    /* 构建返回JSON，包含采样率、采样数和PCM数据 */
    hex_len = (size_t)audio->num_samples * 4 + 512;
    json_data = (char*)safe_malloc(hex_len);
    if (json_data) {
        int offset = snprintf(json_data, hex_len,
            "{\"audio\":{\"sample_rate\":%d,\"num_samples\":%d,\"pcm_hex\":\"",
            audio->sample_rate, audio->num_samples);
        int max_samples = audio->num_samples < 2000 ? audio->num_samples : 2000;
        for (int i = 0; i < max_samples; i++) {
            short pcm = (short)(audio->samples[i] * (audio->samples[i] >= 0 ? 32767.0f : 32768.0f));
            offset += snprintf(json_data + offset, hex_len - (size_t)offset,
                "%02x%02x", (unsigned char)(pcm & 0xFF), (unsigned char)((pcm >> 8) & 0xFF));
        }
        snprintf(json_data + offset, hex_len - (size_t)offset, "\",\"status\":\"ok\"}}");
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
    tts_audio_free(audio);
    return 0;
}
