static int handle_api_post_devices_emergency_stop(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    /* P25修复: 真实调用紧急停止系统 */
    int stopped = 0;
    if (server->emergency_stop_sys) {
        stopped = (emergency_stop_manual_trigger(server->emergency_stop_sys,
                    0, "前端触发设备紧急停止") == 0) ? 1 : 0;
    }
    /* 同时通过安全监控触发停止 */
    if (server->safety_monitor) {
        safety_emergency_stop(server->safety_monitor);
        stopped = 1;
    }
    json_data = (char*)safe_malloc(256);
    if (json_data) {
        snprintf(json_data, 256,
                "{\"devices\":{\"emergency_stop\":%s,\"status\":\"%s\"}}",
                stopped ? "true" : "false",
                stopped ? "all_devices_stopped" : "emergency_stop_system_unavailable");
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = stopped ? 200 : 503;
    }
    return 0;
}
static int handle_api_get_skills(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    int skill_ids[256];
    int count = 0;
    if (server->skill_library) {
        count = skill_library_get_all_skills(server->skill_library, skill_ids, 256);
    }
    size_t buf_size = 16384;
    json_data = (char*)safe_malloc(buf_size);
    if (json_data) {
        int pos = snprintf(json_data, buf_size, "{\"skills\":[");
        for (int i = 0; i < count; i++) {
            SkillRecord sr;
            if (skill_library_get(server->skill_library, skill_ids[i], &sr) == 0) {
                const char* type_names[] = {"atomic","composite","task","meta"};
                pos += snprintf(json_data + pos, buf_size - pos,
                    "%s{\"id\":%d,\"name\":\"%s\",\"desc\":\"%.100s\",\"type\":%d,\"typeName\":\"%s\","
                    "\"domain\":\"%s\",\"enabled\":%d,\"effectiveness\":{\"success_rate\":%.3f,\"execution_count\":%zu}}",
                    i > 0 ? "," : "", sr.skill_id, sr.name, sr.description,
                    sr.type, type_names[sr.type < 4 ? sr.type : 0], sr.domain,
                    sr.enabled, sr.effectiveness.success_rate, sr.effectiveness.execution_count);
            }
        }
        pos += snprintf(json_data + pos, buf_size - pos, "]}");
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
    return 0;
}
static int handle_api_post_skills_execute(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
/* 从空壳占位改为真实技能执行 */
    char* json_data = NULL;
    (void)request_type;
    char skill_name[128] = {0};
    int skill_found = 0;
    if (request_data && request_length > 0 && request_length < 4096) {
        const char* p = (const char*)request_data;
        for (size_t i = 0; i + 7 < request_length; i++) {
            if (p[i]=='\"' && p[i+1]=='s' && p[i+2]=='k' && p[i+3]=='i' &&
                p[i+4]=='l' && p[i+5]=='l' && p[i+6]=='\"' && p[i+7]==':' && p[i+8]=='\"') {
                size_t k = 0; const char* v = p + i + 9;
                while (v < p + request_length && *v && *v != '\"' && k < 127) skill_name[k++] = *v++;
                skill_name[k] = '\0'; skill_found = 1; break;
            }
        }
    }
    if (skill_found && skill_name[0] && server->skill_library) {
        int result = skill_library_execute(server->skill_library, 0, skill_name, NULL);
        json_data = (char*)safe_malloc(384);
        if (json_data) {
            snprintf(json_data, 384,
                "{\"success\":%s,\"skill\":\"%s\",\"result\":%d,\"message\":\"%s\"}",
                result == 0 ? "true" : "false", skill_name, result,
                result == 0 ? "技能执行成功" : "技能执行失败");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = result == 0 ? 200 : 500;
        }
    } else {
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256,
                "{\"success\":false,\"message\":\"%s\"}",
                skill_found ? "技能库未初始化" : "缺少skill参数");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 400;
        }
    }
    return 0;
}
