/* ZSFJJJ-02: json_escape_str 复用 json_escape_into，消除重复逻辑 */
static char* json_escape_str(const char* src) {
    if (!src) return NULL;
    size_t len = strlen(src);
    char* esc = (char*)safe_malloc(len * 2 + 1);
    if (!esc) return NULL;
    json_escape_into(esc, len * 2 + 1, src);
    return esc;
}

static int handle_api_post_skills_search(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    int results[256];
    int result_count = 0;
    char search_tag[SKILL_MAX_TAG_LEN] = "";
    char search_domain[SKILL_MAX_DOMAIN] = "";
    char search_keyword[SKILL_MAX_NAME] = "";

    if (request_data && request_length > 0) {
        parse_json_string(request_data, "tag", search_tag, sizeof(search_tag));
        parse_json_string(request_data, "domain", search_domain, sizeof(search_domain));
        parse_json_string(request_data, "keyword", search_keyword, sizeof(search_keyword));
    }

    if (!server->skill_library) {
        json_data = (char*)safe_malloc(128);
        if (json_data) {
            snprintf(json_data, 128, "{\"success\":false,\"message\":\"技能库未初始化\"}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 500;
        }
        return 0;
    }

    if (search_tag[0]) {
        result_count = skill_library_search_by_tag(server->skill_library, search_tag, results, 256);
    } else if (search_domain[0]) {
        result_count = skill_library_search_by_domain(server->skill_library, search_domain, results, 256);
    } else if (search_keyword[0]) {
        int id = skill_library_find_by_name(server->skill_library, search_keyword);
        if (id > 0) { results[0] = id; result_count = 1; }
    } else {
        result_count = skill_library_get_all_skills(server->skill_library, results, 256);
    }

    json_data = (char*)safe_malloc(65536);
    if (!json_data) return 0;

    char* ptr = json_data;
    int remaining = 65536;
    int n;

    n = snprintf(ptr, remaining, "{\"success\":true,\"count\":%d,\"skills\":[", result_count);
    if (n > 0) { ptr += n; remaining -= n; }

    for (int i = 0; i < result_count && remaining > 256; i++) {
        SkillRecord record;
        memset(&record, 0, sizeof(record));
        if (skill_library_get(server->skill_library, results[i], &record) == 0) {
            if (i > 0) {
                n = snprintf(ptr, remaining, ",");
                if (n > 0) { ptr += n; remaining -= n; }
            }

            char* esc_name = json_escape_str(record.name);
            char* esc_desc = json_escape_str(record.description);
            char* esc_domain = json_escape_str(record.domain);

            n = snprintf(ptr, remaining,
                "{\"id\":%d,\"name\":\"%s\",\"description\":\"%s\",\"domain\":\"%s\","
                "\"type\":%d,\"tag_count\":%d,\"step_count\":%d,"
                "\"success_rate\":%.3f,\"execution_count\":%zu,"
                "\"enabled\":%d,\"version\":%d}",
                record.skill_id,
                esc_name ? esc_name : "",
                esc_desc ? esc_desc : "",
                esc_domain ? esc_domain : "",
                (int)record.type, record.tag_count, record.step_count,
                record.effectiveness.success_rate, record.effectiveness.execution_count,
                record.enabled, record.version);

            safe_free((void**)&esc_name);
            safe_free((void**)&esc_desc);
            safe_free((void**)&esc_domain);

            if (n > 0) { ptr += n; remaining -= n; }
        }
    }

    if (remaining > 4) {
        n = snprintf(ptr, remaining, "]}");
        if (n > 0) { ptr += n; }
    }

    response->data = json_data;
    response->data_length = strlen(json_data);
    response->status_code = 200;
    return 0;
}
static int handle_api_post_skills_compose(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    (void)request_type;
    char* json_data = NULL;
    char name[64] = "";
    char components[256] = "";
    char description[SKILL_MAX_DESC] = "";
    if (request_data && request_length > 0) {
        parse_json_string(request_data, "name", name, sizeof(name));
        parse_json_string(request_data, "components", components, sizeof(components));
        parse_json_string(request_data, "description", description, sizeof(description));
    }

    /* V-010修复: 检查技能库是否可用 */
    if (!server->skill_library) {
        json_data = (char*)safe_malloc(256);
        if (json_data) {
            snprintf(json_data, 256,
                "{\"success\":false,\"error\":\"技能库未初始化\"}");
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 503;
        }
        return 0;
    }

    /* V-010修复: 解析组件ID列表并调用真实技能组合 */
    int skill_ids[SKILL_MAX_PREREQ] = {0};
    int count = 0;
    if (components[0]) {
        char comp_buf[256];
        strncpy(comp_buf, components, sizeof(comp_buf) - 1);
        comp_buf[sizeof(comp_buf) - 1] = '\0';
        char* saveptr = NULL;
/* strtok→strtok_s线程安全 */
        char* token = strtok_s(comp_buf, ",", &saveptr);
        while (token && count < SKILL_MAX_PREREQ) {
            while (*token == ' ') token++;
            int sid = atoi(token);
            if (sid > 0) {
                skill_ids[count++] = sid;
            }
            token = strtok(NULL, ",");
        }
    }

    int new_id = -1;
    if (count > 0 && name[0]) {
        new_id = skill_library_compose(server->skill_library, skill_ids, count,
                                        name, description[0] ? description : NULL);
    }

    json_data = (char*)safe_malloc(512);
    if (json_data) {
        if (new_id > 0) {
            snprintf(json_data, 512,
                "{\"success\":true,\"skill\":{\"id\":%d,\"name\":\"%s\",\"composed\":true,"
                "\"component_count\":%d,\"message\":\"技能组合成功，可通过技能库调用\"}}",
                new_id, name, count);
        } else if (count == 0) {
            snprintf(json_data, 512,
                "{\"success\":false,\"skill\":{\"name\":\"%s\",\"composed\":false,"
                "\"error\":\"缺少有效的组件技能ID列表\"}}",
                name[0] ? name : "composed_skill");
        } else {
            snprintf(json_data, 512,
                "{\"success\":false,\"skill\":{\"name\":\"%s\",\"composed\":false,"
                "\"error\":\"技能组合调用失败（可能是技能库满或重复）\"}}",
                name[0] ? name : "composed_skill");
        }
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = (new_id > 0) ? 200 : 400;
    }
    return 0;
}
static int handle_api_get_safety_status(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    SafetyStats stats;
    memset(&stats, 0, sizeof(stats));
    if (server->safety_monitor) {
        safety_get_stats(server->safety_monitor, &stats);
    }
    SafetyLevel level = server->safety_monitor ? safety_check_status(server->safety_monitor) : SAFETY_LEVEL_NORMAL;
    const char* level_names[] = {"正常","警告","升级","危险","紧急"};
    json_data = (char*)safe_malloc(512);
    if (json_data) {
        snprintf(json_data, 512,
            "{\"level\":%d,\"level_name\":\"%s\",\"safety_score\":%.3f,"
            "\"total_events\":%zu,\"warnings\":%zu,\"critical\":%zu,\"emergencies\":%zu}",
            level, level_names[level < 5 ? level : 0], stats.current_safety_score,
            stats.total_events, stats.warnings, stats.critical, stats.emergencies);
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
/* 安全等级达到警告及以上时通过WebSocket实时推送安全告警 */
    if (server->ws_push_server && level >= SAFETY_LEVEL_WARNING) {
        char alert_json[512];
        snprintf(alert_json, sizeof(alert_json),
            "{\"type\":\"safety_alert\",\"level\":\"%s\",\"score\":%.3f,"
            "\"totalEvents\":%zu,\"timestamp\":%lld}",
            level_names[level < 5 ? level : 0], stats.current_safety_score,
            stats.total_events, (long long)time(NULL));
        ws_push_broadcast_json(server->ws_push_server, alert_json);
    }
    return 0;
}
static int handle_api_get_safety_bounds(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    (void)request_type;
    if (!server->safety_monitor) {
        response->data = string_duplicate("{\"success\":false,\"error\":\"安全监控器未初始化\"}");
        response->data_length = strlen(response->data);
        response->status_code = 503;
        return 0;
    }

/*修复: 检测请求数据是否包含POST更新内容
     * 如果request_data包含JSON body则作为POST设置请求处理
     * 否则作为GET读取请求返回当前边界配置 */
    int is_post_update = 0;
    if (request_data && request_length > 0) {
        /* 使用parse_json_string逐个解析JSON字段，避免sscanf硬编码格式不匹配 */
        char max_speed_str[64] = {0};
        char max_accel_str[64] = {0};
        char max_torque_str[64] = {0};
        char safety_zone_str[64] = {0};
        char collision_dist_str[64] = {0};
        float new_max_speed = 0.0f, new_max_accel = 0.0f, new_max_torque = 0.0f;
        float new_safety_zone = 0.0f, new_collision_dist = 0.0f;
        int parsed = 0;
        if (parse_json_string(request_data, "maxSpeed", max_speed_str, sizeof(max_speed_str)) == 0) {
            new_max_speed = (float)atof(max_speed_str); parsed++;
        }
        if (parse_json_string(request_data, "maxAccel", max_accel_str, sizeof(max_accel_str)) == 0) {
            new_max_accel = (float)atof(max_accel_str); parsed++;
        }
        if (parse_json_string(request_data, "maxTorque", max_torque_str, sizeof(max_torque_str)) == 0) {
            new_max_torque = (float)atof(max_torque_str); parsed++;
        }
        if (parse_json_string(request_data, "safetyZoneRadius", safety_zone_str, sizeof(safety_zone_str)) == 0) {
            new_safety_zone = (float)atof(safety_zone_str); parsed++;
        }
        if (parse_json_string(request_data, "collisionDistance", collision_dist_str, sizeof(collision_dist_str)) == 0) {
            new_collision_dist = (float)atof(collision_dist_str); parsed++;
        }
        if (parsed >= 1) {
            /* 有效的POST请求：解析JSON并更新安全边界 */
            is_post_update = 1;
            PhysicalBoundaries boundaries;
            memset(&boundaries, 0, sizeof(boundaries));
            boundaries.max_velocity = new_max_speed > 0 ? new_max_speed : 2.5f;
            boundaries.max_acceleration = new_max_accel > 0 ? new_max_accel : 5.0f;
            boundaries.max_torque = new_max_torque > 0 ? new_max_torque : 150.0f;
            boundaries.safety_zone_radius = new_safety_zone > 0 ? new_safety_zone : 1.2f;
            boundaries.collision_distance_min = new_collision_dist > 0 ? new_collision_dist : 0.3f;
            boundaries.joint_count = 0;
            int ret = safety_set_physical_boundaries(server->safety_monitor, &boundaries);
            if (ret == 0) {
                char* j = (char*)safe_malloc(384);
                if (j) {
                    snprintf(j, 384,
                        "{\"success\":true,\"message\":\"安全边界配置已更新\",\"bounds\":{"
                        "\"maxSpeed\":%.2f,\"maxAccel\":%.2f,\"maxTorque\":%.2f,"
                        "\"safetyZoneRadius\":%.2f,\"collisionDistance\":%.2f}}",
                        boundaries.max_velocity, boundaries.max_acceleration, boundaries.max_torque,
                        boundaries.safety_zone_radius, boundaries.collision_distance_min);
                    response->data = j;
                    response->data_length = strlen(j);
                    response->status_code = 200;
                }
                return 0;
            }
        }
    }

    if (!is_post_update) {
        /* GET请求：返回当前安全边界配置 */
        char* json_data = (char*)safe_malloc(1024);
        if (json_data) {
/* 从safety_monitor的真实物理边界读取，而非使用硬编码默认值 */
            float max_vel, max_accel, max_torque;
            float safety_zone, collision_dist, joint_range;
            int joint_count;
            if (server->safety_monitor) {
                max_vel = server->safety_monitor->physical_boundaries.max_velocity;
                max_accel = server->safety_monitor->physical_boundaries.max_acceleration;
                max_torque = server->safety_monitor->physical_boundaries.max_torque;
                safety_zone = server->safety_monitor->physical_boundaries.safety_zone_radius;
                collision_dist = server->safety_monitor->physical_boundaries.collision_distance_min;
                joint_count = server->safety_monitor->physical_boundaries.joint_count;
                if (joint_count > 0) {
                    joint_range = server->safety_monitor->physical_boundaries.max_joint_angle[0];
                } else {
                    joint_range = 0.0f;
                }
            } else {
                max_vel = 0.0f; max_accel = 0.0f; max_torque = 0.0f;
                safety_zone = 0.0f; collision_dist = 0.0f;
                joint_range = 0.0f; joint_count = 0;
            }

            int is_active = 0;
            SafetyLevel level = safety_check_status(server->safety_monitor);
            is_active = (level != SAFETY_LEVEL_EMERGENCY) ? 1 : 0;

            SafetyStats stats;
            memset(&stats, 0, sizeof(stats));
            safety_get_stats(server->safety_monitor, &stats);

            snprintf(json_data, 1024,
                "{\"success\":true,\"bounds\":{"
                "\"maxSpeed\":%.2f,\"maxAccel\":%.2f,\"maxTorque\":%.2f,"
                "\"safetyZoneRadius\":%.2f,\"collisionDistance\":%.2f,\"jointRange\":%.2f,"
                "\"jointCount\":%d,"
                "\"status\":\"%s\","
                "\"safetyScore\":%.3f,"
                "\"totalEvents\":%zu,\"warnings\":%zu,\"critical\":%zu,\"emergencies\":%zu"
                "}}",
                max_vel,
                max_accel,
                max_torque,
                safety_zone,
                collision_dist,
                joint_range,
                joint_count,
                is_active ? "active" : "emergency",
                stats.current_safety_score,
                stats.total_events, stats.warnings, stats.critical, stats.emergencies);
            response->data = json_data;
            response->data_length = strlen(json_data);
            response->status_code = 200;
        }
    }
    return 0;
}
static int handle_api_post_safety_emergency_stop(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
/* 紧急停止激活安全模块全面联动 */
    if (server->safety_monitor) safety_emergency_stop(server->safety_monitor);
/* 同步触发内容过滤器紧急拦截模式 */
    if (server->content_filter) {
        ContentFilterResult cf_result;
        memset(&cf_result, 0, sizeof(cf_result));
        content_filter_check(server->content_filter, "EMERGENCY_STOP_ACTIVATED", 24, &cf_result);
        log_warning("[安全] 紧急停止已触发内容过滤器协同锁定");
    }
/* 记录紧急停止审计日志 */
    if (server->audit_logger) {
        audit_log_operation(server->audit_logger, AUDIT_OP_CUSTOM,
            "紧急停止", "SELF-LNN安全系统", "通过API激活紧急停止",
            NULL, NULL, NULL, 1, 0.0f, NULL);
    }
/* WebSocket实时推送安全告警 */
    if (server->ws_push_server) {
        char alert_json[512];
        snprintf(alert_json, sizeof(alert_json),
            "{\"type\":\"safety_alert\",\"level\":\"emergency\","
            "\"message\":\"紧急停止已激活\",\"timestamp\":%lld}", (long long)time(NULL));
        ws_push_broadcast_json(server->ws_push_server, alert_json);
    }
    json_data = (char*)safe_malloc(128);
    if (json_data) {
        snprintf(json_data, 128, "{\"success\":true,\"message\":\"紧急停止已激活\"}");
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
    return 0;
}
