static int handle_api_post_robot_verify_action(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    (void)request_type;
    char* json_data = NULL;
    int robot_id = -1;
    char action_desc[128] = "";
    if (request_data && request_length > 0) {
        parse_json_int(request_data, "robot_id", &robot_id);
        parse_json_string(request_data, "action", action_desc, sizeof(action_desc));
    }
    int verified = 0;
    const char* verify_status = "no_robot";
    if (server->ros_controller && robot_id >= 0) {
        RosRobotInfo info;
        memset(&info, 0, sizeof(info));
        if (ros_robot_controller_get_robot_info(server->ros_controller, robot_id, &info) == 0) {
            /* 实际验证：检查机器人连接状态和错误状态 */
            if (info.connection_state == ROS_ROBOT_CONNECTION_CONNECTED ||
                info.connection_state == ROS_ROBOT_CONNECTION_ACTIVE) {
                if (info.is_emergency_stopped) {
                    verified = 0;
                    verify_status = "emergency_stopped";
                } else {
                    verified = 1;
                    verify_status = "verified";
                }
            } else {
                verify_status = "not_connected";
            }
        }
    } else if (server->robot_instance) {
        verified = 1;
        verify_status = "verified";
    }
    json_data = (char*)safe_malloc(512);
    if (json_data) {
        snprintf(json_data, 512,
            "{\"robot\":{\"action\":\"verify_action\",\"robot_id\":%d,"
            "\"action_desc\":\"%s\",\"verified\":%s,"
            "\"status\":\"%s\"}}",
            robot_id, action_desc, verified ? "true" : "false", verify_status);
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
    return 0;
}
static int handle_api_get_lnn_status(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    int neurons = 0;
    int synapses = 0;
    float lr = 0.01f;
    if (server->lnn_instance) {
        LNNConfig cfg;
        memset(&cfg, 0, sizeof(LNNConfig));
        if (lnn_get_config(server->lnn_instance, &cfg) == 0) {
            neurons = (int)cfg.hidden_size;
            synapses = (int)(cfg.input_size * cfg.hidden_size + cfg.hidden_size * cfg.output_size);
            lr = cfg.learning_rate;
        }
    }
    json_data = (char*)safe_malloc(512);
    if (json_data) {
        snprintf(json_data, 512,
            "{\"lnn\":{\"status\":\"%s\",\"neurons\":%d,\"synapses\":%d,\"learning_rate\":%.4f,\"mode\":\"liquid\"}}",
            neurons > 0 ? "ready" : "not_initialized", neurons, synapses, lr);
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = 200;
    }
    return 0;
}
static int handle_api_post_lnn_parameters(BackendServer* server,
                                   ApiRequestType request_type,
                                   const char* request_data,
                                   size_t request_length,
                                   ApiResponse* response) {
    char* json_data = NULL;
    char params_json[256] = "";
    if (request_data && request_length > 0) {
        size_t copy_len = request_length < 255 ? request_length : 255;
        strncpy(params_json, request_data, copy_len);
        params_json[copy_len] = '\0';
    }
    json_data = (char*)safe_malloc(512);
    if (json_data) {
        /* P25修复: 真实更新LNN配置参数 */
        int updated = 0;
        if (server->lnn_instance && params_json[0]) {
            LNNConfig new_cfg;
            memset(&new_cfg, 0, sizeof(new_cfg));
            if (lnn_get_config(server->lnn_instance, &new_cfg) == 0) {
                /* 尝试从params_json中解析出learning_rate */
                float new_lr = 0.0f;
                if (parse_json_float(params_json, "learning_rate", &new_lr) && new_lr > 0.0f) {
                    new_cfg.learning_rate = new_lr;
                }
                if (lnn_set_config(server->lnn_instance, &new_cfg) == 0) {
                    updated = 1;
                }
            }
        }
        snprintf(json_data, 512,
            "{\"lnn\":{\"parameters\":\"%s\",\"status\":\"%s\"}}",
            updated ? "updated" : "no_change",
            updated ? "ok" : "lnn_not_available");
        response->data = json_data;
        response->data_length = strlen(json_data);
        response->status_code = updated ? 200 : 503;
    }
    return 0;
}
