static int handle_api_post_knowledge_add(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)len;
    char* j = (char*)safe_malloc(512);
    if (j) {
        int ok = 0;
        if (server->knowledge_base) {
            KnowledgeEntry entry; memset(&entry, 0, sizeof(entry));
            char subject_buf[256], predicate_buf[256], object_buf[256];
            if (parse_json_string(data, "subject", subject_buf, 256) == 0 &&
                parse_json_string(data, "predicate", predicate_buf, 256) == 0 &&
                parse_json_string(data, "object", object_buf, 256) == 0) {
                entry.subject = subject_buf; entry.predicate = predicate_buf; entry.object = object_buf;
                ok = (knowledge_base_add(server->knowledge_base, &entry) == 0);
            }
        }
        snprintf(j, 512, "{\"success\":%s,\"knowledge\":{\"added\":%s}}",
            ok ? "true" : "false", ok ? "true" : "false");
        resp->data = j; resp->data_length = strlen(j); resp->status_code = ok ? 200 : 500;
    }
    return 0;
}

static int handle_api_get_knowledge_entry(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt;
    int entry_id = -1;
    if (data && len > 0) {
        parse_json_int(data, "entry_id", &entry_id);
    }
/* 从URL路径中提取entry_id，
     * 例如 /api/knowledge/entry/123 → entry_id = 123 */
    if (entry_id < 0 && server->request_path[0]) {
        const char* prefix = "/api/knowledge/entry/";
        const char* pos = strstr(server->request_path, prefix);
        if (pos) {
            pos += strlen(prefix);
            if (*pos >= '0' && *pos <= '9') {
                entry_id = atoi(pos);
            }
        }
    }
    if (!server->knowledge_base) {
        char* j = (char*)safe_malloc(512);
        if (j) {
            snprintf(j, 512, "{\"success\":false,\"knowledge_entry\":{\"error\":\"知识库不可用\",\"entry_id\":%d}}", entry_id);
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    if (entry_id < 0) {
        size_t total = 0, mem = 0;
        knowledge_base_get_stats(server->knowledge_base, &total, &mem);
        char* j = (char*)safe_malloc(512);
        if (j) {
            snprintf(j, 512, "{\"success\":true,\"knowledge_entry\":{\"count\":%zu,\"memory_bytes\":%zu,\"hint\":\"请提供entry_id参数查询特定条目\"}}", total, mem);
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
        }
        return 0;
    }
    KnowledgeEntry entry;
    memset(&entry, 0, sizeof(KnowledgeEntry));
    int result = knowledge_base_get_by_id(server->knowledge_base, entry_id, &entry);
    char* j = (char*)safe_malloc(2048);
    if (j) {
        if (result == 0 && entry.subject) {
            snprintf(j, 2048, "{\"success\":true,\"knowledge_entry\":{"
                "\"entry_id\":%d,\"subject\":\"%s\",\"predicate\":\"%s\",\"object\":\"%s\","
                "\"type\":%d,\"confidence\":%d,\"weight\":%.4f,\"timestamp\":%ld}}",
                entry_id,
                entry.subject ? entry.subject : "",
                entry.predicate ? entry.predicate : "",
                entry.object ? entry.object : "",
                (int)entry.type, (int)entry.confidence, entry.weight, entry.timestamp);
        } else {
            snprintf(j, 512, "{\"success\":false,\"knowledge_entry\":{\"entry_id\":%d,\"error\":\"条目不存在\"}}", entry_id);
        }
        resp->data = j; resp->data_length = strlen(j); resp->status_code = (result == 0) ? 200 : 404;
    }
    return 0;
}

static int handle_api_get_knowledge_stats_api(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)data; (void)len;
    char* j = (char*)safe_malloc(4096);
    if (j) {
        size_t total = 0, mem = 0;
        if (server->knowledge_base) knowledge_base_get_stats(server->knowledge_base, &total, &mem);
/* 从知识库查询领域分类用于前端动态展示 */
        int domain_count = 0;
        char domains_json[2048] = {0};
        int dpos = 0;
        if (server->knowledge_base && total > 0) {
            KnowledgeEntry domain_entries[64];
            KnowledgeQuery dq;
            memset(&dq, 0, sizeof(dq));
            dq.type_filter = 2; /* 概念关系/领域 */
            int dc = knowledge_base_query(server->knowledge_base, &dq, domain_entries, 64);
            /* 收集唯一领域名 */
            char domain_names[32][64];
            int domain_counts[32] = {0};
            for (int i = 0; i < dc && domain_count < 32; i++) {
                const char* dn = domain_entries[i].subject ? domain_entries[i].subject : "";
                if (dn[0]) {
                    int found = 0;
                    for (int jj = 0; jj < domain_count; jj++) {
                        if (strcmp(domain_names[jj], dn) == 0) { domain_counts[jj]++; found = 1; break; }
                    }
                    if (!found && domain_count < 32) {
                        strncpy(domain_names[domain_count], dn, 63);
                        domain_names[domain_count][63] = '\0';
                        domain_counts[domain_count] = 1;
                        domain_count++;
                    }
                }
            }
            /* 输出领域JSON */
            for (int i = 0; i < domain_count && dpos < (int)sizeof(domains_json) - 128; i++) {
                dpos += snprintf(domains_json + dpos, sizeof(domains_json) - (size_t)dpos,
                    "%s{\"name\":\"%s\",\"count\":%d}",
                    i > 0 ? "," : "", domain_names[i], domain_counts[i]);
            }
        }
        snprintf(j, 4096, "{\"stats\":{\"total_entries\":%zu,\"memory_bytes\":%zu,\"status\":\"%s\",\"domain_count\":%d,\"domains\":[%s]}}",
            total, mem, server->knowledge_base ? "available" : "unavailable",
            domain_count, domains_json);
        resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
    }
    return 0;
}

static int handle_api_post_knowledge_export(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)len;
    if (!server->knowledge_base) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"export\":{\"error\":\"知识库不可用\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    char format[32] = "json";
    int max_entries = 100;
    if (data && len > 0) {
        parse_json_string(data, "format", format, sizeof(format));
        parse_json_int(data, "max_entries", &max_entries);
    }
    if (max_entries <= 0) max_entries = 100;
    if (max_entries > 10000) max_entries = 10000;
    size_t total = 0, mem = 0;
    knowledge_base_get_stats(server->knowledge_base, &total, &mem);
    int export_count = (int)(total < (size_t)max_entries ? total : (size_t)max_entries);
    KnowledgeEntry* entries = (KnowledgeEntry*)safe_calloc(export_count, sizeof(KnowledgeEntry));
    char* j = (char*)safe_malloc(65536);
    if (!j) {
        safe_free((void**)&entries);
        return 0;
    }
    if (entries) {
        KnowledgeQuery q;
        memset(&q, 0, sizeof(KnowledgeQuery));
        q.type_filter = -1;
        int queried = knowledge_base_query(server->knowledge_base, &q, entries, export_count);
        char* buf = j;
        size_t remaining = 65536;
        int written = snprintf(buf, remaining,
            "{\"success\":true,\"export\":{\"format\":\"%s\",\"total_entries\":%zu,\"exported\":%d,\"entries\":[",
            format, total, queried);
        if (written < 0 || (size_t)written >= remaining) written = 0;
        buf += written; remaining -= (size_t)written;
        for (int i = 0; i < queried && remaining > 256; i++) {
            if (entries[i].subject && entries[i].predicate) {
                int w = snprintf(buf, remaining,
                    "%s{\"id\":%d,\"s\":\"%s\",\"p\":\"%s\",\"o\":\"%s\",\"t\":%d,\"c\":%d}",
                    i > 0 ? "," : "",
                    i + 1,
                    entries[i].subject,
                    entries[i].predicate,
                    entries[i].object ? entries[i].object : "",
                    (int)entries[i].type,
                    (int)entries[i].confidence);
                if (w > 0 && (size_t)w < remaining) { buf += w; remaining -= (size_t)w; }
            }
        }
        snprintf(buf, remaining, "],\"ready\":true}}");
        safe_free((void**)&entries);
    } else {
        snprintf(j, 512, "{\"success\":true,\"export\":{\"format\":\"%s\",\"entries\":%zu,\"ready\":true,\"hint\":\"内存不足，仅返回摘要\"}}",
            format, total);
    }
    resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
    return 0;
}

static int handle_api_post_knowledge_delete(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt;
    int entry_id = -1;
    if (data && len > 0) {
        parse_json_int(data, "entry_id", &entry_id);
    }
    /* API-4修复: 从URL路径中提取entry_id，
     * 兼容DELETE /api/knowledge/entry/123的调用方式 */
    if (entry_id < 0 && server->request_path[0]) {
        const char* prefix = "/api/knowledge/entry/";
        const char* pos = strstr(server->request_path, prefix);
        if (pos) {
            pos += strlen(prefix);
            if (*pos >= '0' && *pos <= '9') {
                entry_id = atoi(pos);
            }
        }
    }
    if (!server->knowledge_base) {
        char* j = (char*)safe_malloc(384);
        if (j) {
            snprintf(j, 384, "{\"success\":false,\"knowledge_delete\":{\"entry_id\":%d,\"error\":\"知识库不可用\"}}", entry_id);
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    /* 知识库清空功能：当请求中clear_all=1时，清空全部知识条目 */
    {
        int clear_all_flag = 0;
        if (data && len > 0) {
            parse_json_int(data, "clear_all", &clear_all_flag);
        }
        if (clear_all_flag) {
            size_t total_before = 0, mem_before = 0;
            knowledge_base_get_stats(server->knowledge_base, &total_before, &mem_before);
            knowledge_base_clear(server->knowledge_base);
            size_t total_after = 0, mem_after = 0;
            knowledge_base_get_stats(server->knowledge_base, &total_after, &mem_after);
            size_t deleted_count = total_before - total_after;
            char* j = (char*)safe_malloc(384);
            if (j) {
                snprintf(j, 384, "{\"success\":true,\"knowledge\":{\"deleted_count\":%zu,\"remaining\":%zu}}",
                    deleted_count, total_after);
                resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
            }
            log_info("[知识库] 清空全部知识条目: 删除%zu条，剩余%zu条", deleted_count, total_after);
            return 0;
        }
    }
    if (entry_id < 0) {
        char subject[256] = "";
        char predicate[256] = "";
        if (data && len > 0) {
            parse_json_string(data, "subject", subject, sizeof(subject));
            parse_json_string(data, "predicate", predicate, sizeof(predicate));
        }
        size_t total = 0, mem = 0;
        knowledge_base_get_stats(server->knowledge_base, &total, &mem);
        char* j = (char*)safe_malloc(512);
        if (j) {
            snprintf(j, 512, "{\"success\":false,\"knowledge_delete\":{\"error\":\"请提供entry_id参数\",\"total_entries\":%zu,\"hint\":\"使用entry_id指定要删除的知识条目\"}}", total);
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 400;
        }
        return 0;
    }
    int result = knowledge_base_remove(server->knowledge_base, entry_id);
    char* j = (char*)safe_malloc(384);
    if (j) {
        if (result == 0) {
            snprintf(j, 384, "{\"success\":true,\"knowledge_delete\":{\"entry_id\":%d,\"status\":\"已删除\"}}", entry_id);
            resp->status_code = 200;
        } else {
            snprintf(j, 384, "{\"success\":false,\"knowledge_delete\":{\"entry_id\":%d,\"error\":\"删除失败，条目不存在\"}}", entry_id);
            resp->status_code = 404;
        }
        resp->data = j; resp->data_length = strlen(j);
    }
    return 0;
}

/* M-013修复: 知识库语义搜索处理器 —— 融合多策略搜索：相似度匹配 + CfC语义嵌入 + TF-IDF全文检索 */
static int handle_api_post_knowledge_search(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)len;
    char query[1024] = {0};
    float threshold = 0.3f;
    int max_results = 50;
    if (data && len > 0) {
        parse_json_string(data, "query", query, sizeof(query));
        float t = 0.0f;
        if (parse_json_float(data, "threshold", &t) == 0) threshold = t;
        parse_json_int(data, "max_results", &max_results);
    }
    if (max_results <= 0) max_results = 50;
    if (max_results > 500) max_results = 500;
    if (threshold < 0.0f) threshold = 0.0f;
    if (threshold > 1.0f) threshold = 1.0f;

    if (!server->knowledge_base || query[0] == '\0') {
        char* j = (char*)safe_malloc(384);
        if (j) {
            snprintf(j, 384, "{\"success\":false,\"search\":{\"error\":\"%s\",\"results\":}}",
                !server->knowledge_base ? "知识库不可用" : "查询为空");
            resp->data = j; resp->data_length = strlen(j);
            resp->status_code = !server->knowledge_base ? 503 : 400;
        }
        return 0;
    }

    /* 分配搜索结果缓冲区（三路搜索结果，需要独立去重） */
    const int max_each = 64;
    KnowledgeEntry* sim_results   = (KnowledgeEntry*)safe_calloc((size_t)max_each, sizeof(KnowledgeEntry));
    KnowledgeEntry* cfc_results   = (KnowledgeEntry*)safe_calloc((size_t)max_each, sizeof(KnowledgeEntry));
    KnowledgeEntry* tfidf_results = (KnowledgeEntry*)safe_calloc((size_t)max_each, sizeof(KnowledgeEntry));
    float* tfidf_scores           = (float*)safe_calloc((size_t)max_each, sizeof(float));
    if (!sim_results || !cfc_results || !tfidf_results || !tfidf_scores) {
        safe_free((void**)&sim_results); safe_free((void**)&cfc_results);
        safe_free((void**)&tfidf_results); safe_free((void**)&tfidf_scores);
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"search\":{\"error\":\"内存不足\",\"results\":}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 500;
        }
        return 0;
    }

    /* 策略1: 相似度匹配 */
    int sim_cnt = knowledge_base_search_similar(server->knowledge_base,
        query, NULL, NULL, threshold, sim_results, (size_t)max_each);
    if (sim_cnt < 0) sim_cnt = 0;

    /* 策略2: CfC语义嵌入搜索 */
    int cfc_cnt = knowledge_base_cfc_semantic_search(server->knowledge_base,
        query, threshold, cfc_results, (size_t)max_each);
    if (cfc_cnt < 0) cfc_cnt = 0;

    /* 策略3: TF-IDF全文检索 */
    int tfidf_cnt = knowledge_base_search_tfidf(server->knowledge_base,
        query, tfidf_results, (size_t)max_each, tfidf_scores, 0.01f);
    if (tfidf_cnt < 0) tfidf_cnt = 0;

    /* 构建去重后的合并结果JSON */
    char* j = (char*)safe_malloc(65536);
    if (!j) {
        safe_free((void**)&sim_results); safe_free((void**)&cfc_results);
        safe_free((void**)&tfidf_results); safe_free((void**)&tfidf_scores);
        char* errj = (char*)safe_malloc(256);
        if (errj) {
            snprintf(errj, 256, "{\"success\":false,\"search\":{\"error\":\"内存不足\",\"results\":}}");
            resp->data = errj; resp->data_length = strlen(errj); resp->status_code = 500;
        }
        return 0;
    }

    /* 用于去重的条目内容哈希表 */
    char seen_subjects[128][256];
    int seen_count = 0;
    int output_count = 0;

    size_t buf_remaining = 65536;
    char* buf = j;
    int header_written = snprintf(buf, buf_remaining,
        "{\"success\":true,\"search\":{\"query\":\"%s\",\"threshold\":%.2f,\"strategies\":"
        "{\"similar\":%d,\"cfc_semantic\":%d,\"tfidf\":%d},\"results\":[",
        query, threshold, sim_cnt, cfc_cnt, tfidf_cnt);
    if (header_written > 0 && (size_t)header_written < buf_remaining) {
        buf += header_written; buf_remaining -= (size_t)header_written;
    }

    /* 按优先级输出: CfC语义 > TF-IDF > 相似度匹配，保证高质量结果优先 */
    typedef struct { KnowledgeEntry* entries; int count; } SearchBucket;
    SearchBucket buckets[3];
    buckets[0].entries = cfc_results;   buckets[0].count = cfc_cnt;
    buckets[1].entries = tfidf_results; buckets[1].count = tfidf_cnt;
    buckets[2].entries = sim_results;   buckets[2].count = sim_cnt;

    for (int bi = 0; bi < 3 && output_count < max_results; bi++) {
        for (int ei = 0; ei < buckets[bi].count && output_count < max_results; ei++) {
            KnowledgeEntry* entry = &buckets[bi].entries[ei];
            if (!entry->subject || entry->subject[0] == '\0') continue;
            /* 去重检查 */
            int duplicate = 0;
            for (int s = 0; s < seen_count && !duplicate; s++) {
                if (strcmp(seen_subjects[s], entry->subject) == 0) duplicate = 1;
            }
            if (duplicate) continue;
            if (seen_count < 128) {
                strncpy(seen_subjects[seen_count], entry->subject, 255);
                seen_subjects[seen_count][255] = '\0';
                seen_count++;
            }
            int w = snprintf(buf, buf_remaining,
                "%s{\"s\":\"%s\",\"p\":\"%s\",\"o\":\"%s\",\"t\":%d,\"c\":%d,\"w\":%.3f,\"src\":%d}",
                output_count > 0 ? "," : "",
                entry->subject,
                entry->predicate ? entry->predicate : "",
                entry->object ? entry->object : "",
                (int)entry->type,
                (int)entry->confidence,
                entry->weight,
                (int)entry->source);
            if (w > 0 && (size_t)w < buf_remaining) { buf += w; buf_remaining -= (size_t)w; }
            output_count++;
        }
    }

    snprintf(buf, buf_remaining, "],\"total\":%d}}", output_count);

    safe_free((void**)&sim_results); safe_free((void**)&cfc_results);
    safe_free((void**)&tfidf_results); safe_free((void**)&tfidf_scores);

    resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
    return 0;
}

/* M-013修复: 知识库批量导入处理器 —— 解析JSON数组批量导入知识条目 */
static int handle_api_post_knowledge_import(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)len;
    if (!server->knowledge_base) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"import\":{\"error\":\"知识库不可用\",\"imported\":0}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    if (!data || len == 0) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"import\":{\"error\":\"导入数据为空\",\"imported\":0}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 400;
        }
        return 0;
    }

    int imported = 0;
    int failed = 0;
    int skipped = 0;

    /* 检查是否是JSON种子知识文件路径导入 */
    char filepath[512] = {0};
    parse_json_string(data, "filepath", filepath, sizeof(filepath));
    if (filepath[0] != '\0') {
        int loaded = knowledge_base_load_from_file(server->knowledge_base, filepath);
        if (loaded > 0) imported = loaded;
        else if (loaded == 0) skipped = 1;
        else failed = 1;
        /* 同时尝试导入到知识图谱 */
        {
            void* kg_ptr = selflnn_get_knowledge_graph();
            if (kg_ptr) {
                knowledge_graph_import_from_knowledge_base((KnowledgeGraph*)kg_ptr, server->knowledge_base);
            }
        }
        char* j = (char*)safe_malloc(512);
        if (j) {
            snprintf(j, 512,
                "{\"success\":true,\"import\":{\"method\":\"file\",\"filepath\":\"%s\","
                "\"imported\":%d,\"failed\":%d,\"skipped\":%d}}",
                filepath, imported, failed, skipped);
            resp->data = j; resp->data_length = strlen(j); resp->status_code = (imported > 0) ? 200 : 400;
        }
        return 0;
    }

    /* 解析JSON entries数组批量导入 */
    int entry_count = 0;
    parse_json_int(data, "entry_count", &entry_count);

    /* 尝试解析entries数组中的每个元素 */
    const char* entries_begin = NULL;
    {
        const char* key_search = data;
        while ((key_search = strstr(key_search, "\"entries\"")) != NULL) {
            const char* bracket = strchr(key_search + 9, '[');
            if (bracket) { entries_begin = bracket; break; }
            key_search += 9;
        }
    }

    if (entries_begin) {
        entries_begin++; /* 跳过[ */
        const char* p = entries_begin;
        int parsed = 0;
        const int max_batch = 1000;
        while (parsed < max_batch) {
            const char* obj_start = strchr(p, '{');
            if (!obj_start) break;
            const char* obj_end = strchr(obj_start, '}');
            if (!obj_end) break;
            size_t obj_len = (size_t)(obj_end - obj_start) + 1;
            if (obj_len == 1) { p = obj_end + 1; continue; }

            char subject[256] = {0}, predicate[256] = {0}, object[256] = {0};
            char type_str[32] = {0}, conf_str[32] = {0};
            float weight = 1.0f;

            /* 提取json字段：复制JSON对象到临时缓冲区并使用parse_json_string */
            {
                char temp[1024];
                size_t cp_len = obj_len < sizeof(temp) - 1 ? obj_len : sizeof(temp) - 1;
                memcpy(temp, obj_start, cp_len);
                temp[cp_len] = '\0';
                { parse_json_string(temp, "s", subject, sizeof(subject));
                  parse_json_string(temp, "p", predicate, sizeof(predicate));
                  parse_json_string(temp, "o", object, sizeof(object));
                  parse_json_string(temp, "t", type_str, sizeof(type_str));
                  parse_json_string(temp, "c", conf_str, sizeof(conf_str)); }
                { const char* w_key = strstr(temp, "\"w\":");
                  if (w_key) {
                      const char* w_val = w_key + 4;
                      while (*w_val == ' ' || *w_val == ':') w_val++;
                      weight = (float)atof(w_val);
                  } }
            }

            /* 字段回退：无s则用subject */
            if (subject[0] == '\0') {
                const char* sj_key = strstr(obj_start, "\"subject\"");
                if (sj_key) { const char* sv = strchr(sj_key + 9, '\"'); if (sv) { sv++;
                    char* dest = subject; while (*sv && *sv != '\"' && (dest - subject) < 255) *dest++ = *sv++;
                    *dest = '\0'; } }
            }
            if (predicate[0] == '\0') {
                const char* pj_key = strstr(obj_start, "\"predicate\"");
                if (pj_key) { const char* pv = strchr(pj_key + 11, '\"'); if (pv) { pv++;
                    char* dest = predicate; while (*pv && *pv != '\"' && (dest - predicate) < 255) *dest++ = *pv++;
                    *dest = '\0'; } }
            }
            if (object[0] == '\0') {
                const char* oj_key = strstr(obj_start, "\"object\"");
                if (oj_key) { const char* ov = strchr(oj_key + 8, '\"'); if (ov) { ov++;
                    char* dest = object; while (*ov && *ov != '\"' && (dest - object) < 255) *dest++ = *ov++;
                    *dest = '\0'; } }
            }

            if (subject[0] != '\0' && predicate[0] != '\0') {
                KnowledgeEntry entry;
                memset(&entry, 0, sizeof(KnowledgeEntry));
                entry.subject = subject; entry.predicate = predicate; entry.object = object;

                /* 解析类型 */
                if (type_str[0]) {
                    if (strcmp(type_str, "FACT") == 0 || strcmp(type_str, "fact") == 0) entry.type = KNOWLEDGE_FACT;
                    else if (strcmp(type_str, "RULE") == 0 || strcmp(type_str, "rule") == 0) entry.type = KNOWLEDGE_RULE;
                    else if (strcmp(type_str, "CONCEPT") == 0 || strcmp(type_str, "concept") == 0) entry.type = KNOWLEDGE_CONCEPT;
                    else if (strcmp(type_str, "RELATION") == 0 || strcmp(type_str, "relation") == 0) entry.type = KNOWLEDGE_RELATION;
                    else if (strcmp(type_str, "OBSERVATION") == 0 || strcmp(type_str, "observation") == 0) entry.type = KNOWLEDGE_OBSERVATION;
                }
                /* 解析置信度 */
                if (conf_str[0]) {
                    if (strcmp(conf_str, "HIGH") == 0 || strcmp(conf_str, "high") == 0) entry.confidence = CONFIDENCE_HIGH;
                    else if (strcmp(conf_str, "MEDIUM") == 0 || strcmp(conf_str, "medium") == 0) entry.confidence = CONFIDENCE_MEDIUM;
                    else if (strcmp(conf_str, "LOW") == 0 || strcmp(conf_str, "low") == 0) entry.confidence = CONFIDENCE_LOW;
                }
                entry.weight = weight;
                entry.source = SOURCE_USER;
                entry.timestamp = (long)time(NULL);

                if (knowledge_base_add(server->knowledge_base, &entry) == 0) {
                    imported++;
                } else {
                    failed++;
                }
            } else {
                skipped++;
            }

            parsed++;
            p = obj_end + 1;
            if (*p == ',') p++;
            while (*p == ' ' || *p == '\n' || *p == '\r' || *p == '\t') p++;
            if (*p == ']' || *p == '\0') break;
        }
    } else if (entry_count <= 0) {
        /* 无entries数组，尝试单条导入 */
        char subject[256] = {0}, predicate[256] = {0}, object[256] = {0};
        parse_json_string(data, "subject", subject, sizeof(subject));
        parse_json_string(data, "predicate", predicate, sizeof(predicate));
        parse_json_string(data, "object", object, sizeof(object));
        if (subject[0] != '\0' && predicate[0] != '\0') {
            KnowledgeEntry entry;
            memset(&entry, 0, sizeof(KnowledgeEntry));
            entry.subject = subject; entry.predicate = predicate; entry.object = object;
            entry.type = KNOWLEDGE_FACT;
            entry.confidence = CONFIDENCE_HIGH;
            entry.weight = 1.0f;
            entry.source = SOURCE_USER;
            entry.timestamp = (long)time(NULL);
            if (knowledge_base_add(server->knowledge_base, &entry) == 0) imported++;
            else failed++;
        } else {
            skipped++;
        }
    }

    /* 导入后同步到知识图谱 */
    if (imported > 0) {
        void* kg_ptr = selflnn_get_knowledge_graph();
        if (kg_ptr) {
            knowledge_graph_import_from_knowledge_base((KnowledgeGraph*)kg_ptr, server->knowledge_base);
        }
    }

    char* j = (char*)safe_malloc(1024);
    if (j) {
        snprintf(j, 1024,
            "{\"success\":true,\"import\":{\"method\":\"batch\",\"imported\":%d,\"failed\":%d,\"skipped\":%d,\"total\":%d}}",
            imported, failed, skipped, imported + failed + skipped);
        resp->data = j; resp->data_length = strlen(j);
        resp->status_code = (imported > 0) ? 200 : 400;
    }
    return 0;
}

static int handle_api_post_memory_add(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt;
    if (!server->memory_manager) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"memory_add\":{\"error\":\"记忆管理器不可用\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    char key[256] = {0};
    char content[4096] = {0};
    float strength = 1.0f;
    int priority = 0;
    if (data && len > 0) {
        parse_json_string(data, "key", key, sizeof(key));
        parse_json_string(data, "content", content, sizeof(content));
        float s = 0.0f;
        if (parse_json_float(data, "strength", &s) == 0) strength = s;
        int p = 0;
        if (parse_json_int(data, "priority", &p) == 0) priority = p;
    }
    if (key[0] == '\0') {
        snprintf(key, sizeof(key), "auto_%ld", (long)time(NULL));
    }
    float store_data[256] = {0};
    size_t content_len = strlen(content);
    for (size_t i = 0; i < content_len && i < 256; i++) store_data[i] = (float)(unsigned char)content[i];
    size_t data_size = content_len > 256 ? 256 : content_len;
    if (data_size < 1) data_size = 1;
    int result = memory_manager_store(server->memory_manager, key, store_data, data_size, priority, strength);
    size_t total_mem = 0;
    float ratio = 0.0f, level = 0.0f;
    memory_manager_get_stats(server->memory_manager, &total_mem, &ratio, &level);
    char* j = (char*)safe_malloc(512);
    if (j) {
        snprintf(j, 512, "{\"success\":%s,\"memory_add\":{\"key\":\"%s\",\"stored\":%s,\"total_memories\":%zu}}",
            result == 0 ? "true" : "false",
            key,
            result == 0 ? "true" : "false",
            total_mem);
        resp->data = j; resp->data_length = strlen(j); resp->status_code = result == 0 ? 200 : 500;
    }
    return 0;
}

static int handle_api_get_memory_entry(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt;
    if (!server->memory_manager) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"memory_entry\":{\"error\":\"记忆管理器不可用\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    char key[256] = {0};
    if (data && len > 0) {
        parse_json_string(data, "key", key, sizeof(key));
    }
/* 从URL路径中提取entry key，
     * 例如 /api/memory/entry/MyKey → key = "MyKey" */
    if (key[0] == '\0' && server->request_path[0]) {
        const char* prefix = "/api/memory/entry/";
        const char* pos = strstr(server->request_path, prefix);
        if (pos) {
            pos += strlen(prefix);
            if (*pos) {
                const char* end = pos;
                while (*end && *end != '/' && *end != '?' && *end != ' ') end++;
                size_t klen = (size_t)(end - pos);
                if (klen > 0 && klen < sizeof(key)) {
                    memcpy(key, pos, klen);
                    key[klen] = '\0';
                }
            }
        }
    }
    if (key[0] == '\0') {
        size_t total_mem = 0;
        float ratio = 0.0f, level = 0.0f;
        memory_manager_get_stats(server->memory_manager, &total_mem, &ratio, &level);
        char* j = (char*)safe_malloc(512);
        if (j) {
            snprintf(j, 512, "{\"success\":true,\"memory_entry\":{\"total_memories\":%zu,\"consolidation_ratio\":%.4f,\"hint\":\"请提供key参数查询特定记忆条目\"}}",
                total_mem, ratio);
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
        }
        return 0;
    }
    float retrieved_data[256];
    float strength = 0.0f;
    int memory_type = 0;
    int result = memory_manager_retrieve(server->memory_manager, key, retrieved_data, 256, &strength, &memory_type);
    char* j = (char*)safe_malloc(2048);
    if (j) {
        if (result == 0) {
            char content[257] = {0};
            for (int i = 0; i < 256 && retrieved_data[i] != 0.0f; i++) {
                unsigned char ch = (unsigned char)(int)retrieved_data[i];
                if (ch >= 32 && ch < 127) content[i] = (char)ch;
            }
            snprintf(j, 2048, "{\"success\":true,\"memory_entry\":{"
                "\"key\":\"%s\",\"found\":true,\"strength\":%.4f,"
                "\"memory_type\":%d,\"content_preview\":\"%.128s\"}}",
                key, strength, memory_type, content);
            resp->status_code = 200;
        } else {
            snprintf(j, 512, "{\"success\":false,\"memory_entry\":{\"key\":\"%s\",\"found\":false,\"error\":\"记忆条目不存在\"}}", key);
            resp->status_code = 404;
        }
        resp->data = j; resp->data_length = strlen(j);
    }
    return 0;
}

/* ZSFKKK-修复(HIGH-04): 删除记忆条目 DELETE /api/memory/entry/{key} */
static int handle_api_delete_memory_entry(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)data; (void)len;
    if (!server->memory_manager) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"memory_delete\":{\"error\":\"记忆管理器不可用\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    char key[256] = {0};
    /* 从URL路径中提取entry key /api/memory/entry/XXX */
    if (server->request_path[0]) {
        const char* prefix = "/api/memory/entry/";
        const char* pos = strstr(server->request_path, prefix);
        if (pos) {
            pos += strlen(prefix);
            if (*pos) {
                const char* end = pos;
                while (*end && *end != '/' && *end != '?' && *end != ' ') end++;
                size_t klen = (size_t)(end - pos);
                if (klen > 0 && klen < sizeof(key)) {
                    memcpy(key, pos, klen);
                    key[klen] = '\0';
                }
            }
        }
    }
    if (key[0] == '\0') {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"memory_delete\":{\"error\":\"请提供key参数指定要删除的记忆条目\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 400;
        }
        return 0;
    }
    int result = memory_manager_forget(server->memory_manager, key);
    char* j = (char*)safe_malloc(384);
    if (j) {
        if (result == 0) {
            snprintf(j, 384, "{\"success\":true,\"memory_delete\":{\"key\":\"%s\",\"status\":\"已删除\"}}", key);
            resp->status_code = 200;
        } else {
            snprintf(j, 384, "{\"success\":false,\"memory_delete\":{\"key\":\"%s\",\"error\":\"删除失败，记忆条目不存在\"}}", key);
            resp->status_code = 404;
        }
        resp->data = j; resp->data_length = strlen(j);
    }
    return 0;
}

/* ZSFKKK-修复(HIGH-04): 更新记忆条目 PUT /api/memory/entry/{key} */
static int handle_api_put_memory_entry(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt;
    if (!server->memory_manager) {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"memory_update\":{\"error\":\"记忆管理器不可用\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    char key[256] = {0};
    /* 从URL路径中提取entry key /api/memory/entry/XXX */
    if (server->request_path[0]) {
        const char* prefix = "/api/memory/entry/";
        const char* pos = strstr(server->request_path, prefix);
        if (pos) {
            pos += strlen(prefix);
            if (*pos) {
                const char* end = pos;
                while (*end && *end != '/' && *end != '?' && *end != ' ') end++;
                size_t klen = (size_t)(end - pos);
                if (klen > 0 && klen < sizeof(key)) {
                    memcpy(key, pos, klen);
                    key[klen] = '\0';
                }
            }
        }
    }
    if (key[0] == '\0') {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"memory_update\":{\"error\":\"请提供key参数指定要更新的记忆条目\"}}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 400;
        }
        return 0;
    }
    /* 解析请求体中的更新数据 */
    float update_data[256] = {0};
    int data_size = 0;
    if (data && len > 0) {
        /* 尝试解析value字段作为浮点数数组 */
        const char* val_start = strstr(data, "\"value\"");
        if (val_start) {
            val_start = strchr(val_start, '[');
            if (val_start) {
                val_start++;
                const char* val_end = strchr(val_start, ']');
                if (val_end && data_size < 256) {
                    const char* p = val_start;
                    while (p < val_end && data_size < 256) {
                        while (*p == ' ' || *p == ',') p++;
                        if (p >= val_end) break;
                        char* np;
                        update_data[data_size++] = (float)strtod(p, &np);
                        p = np;
                    }
                }
            }
        }
    }
    int result = memory_manager_update(server->memory_manager, key, update_data, 
                                       data_size > 0 ? data_size : 256, 0.1f);
    char* j = (char*)safe_malloc(384);
    if (j) {
        if (result == 0) {
            snprintf(j, 384, "{\"success\":true,\"memory_update\":{\"key\":\"%s\",\"data_size\":%d,\"status\":\"已更新\"}}", key, data_size > 0 ? data_size : 256);
            resp->status_code = 200;
        } else {
            snprintf(j, 384, "{\"success\":false,\"memory_update\":{\"key\":\"%s\",\"error\":\"更新失败，记忆条目不存在\"}}", key);
            resp->status_code = 404;
        }
        resp->data = j; resp->data_length = strlen(j);
    }
    return 0;
}

