static int handle_api_post_dialogue_send(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt;
    char msg[1024] = {0};
    float temperature = 0.8f;
    int max_length = 256;
    int top_k = 50;
    int memory = 5;
    if (data && len > 0 && len < 8192) {
        const char* p = (const char*)data;
        for (size_t i = 0; i + 11 < len; i++) {
            if (p[i]=='\"' && p[i+1]=='m' && p[i+2]=='e' && p[i+3]=='s' &&
                p[i+4]=='s' && p[i+5]=='a' && p[i+6]=='g' && p[i+7]=='e' &&
                p[i+8]=='\"' && p[i+9]==':' && p[i+10]=='\"') {
                size_t k = 0; const char* v = p + i + 11;
                while (v < p + len && *v && *v != '\"' && k < 1023) msg[k++] = *v++;
                msg[k] = '\0'; break;
            }
        }
/* 解析temperature/max_length/top_k/memory参数 */
        parse_json_float(data, "temperature", &temperature);
        parse_json_int(data, "max_length", &max_length);
        parse_json_int(data, "top_k", &top_k);
        parse_json_int(data, "memory", &memory);
        if (msg[0] == '\0') {
            size_t cp = len < 1023 ? len : 1023;
            memcpy(msg, p, cp); msg[cp] = '\0';
        }
    }
    if (msg[0] == '\0') {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"reply\":\"输入内容为空\",\"confidence\":0.0}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 400;
        }
        return 0;
    }

    /* 安全过滤 */
    if (server->content_filter) {
        ContentFilterResult filter_result;
        memset(&filter_result, 0, sizeof(ContentFilterResult));
        if (content_filter_check(server->content_filter, msg, strlen(msg), &filter_result) == 0) {
            if (filter_result.blocked) {
                char* j = (char*)safe_malloc(256);
                if (j) {
                    snprintf(j, 256, "{\"success\":false,\"reply\":\"输入内容被安全过滤拦截\",\"confidence\":0.0,\"safety_filtered\":true}");
                    resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
                }
                return 0;
            }
        }
    }

    /* 使用对话处理器进行真实对话（单一LNN模型） */
    if (!server->dialogue_processor && server->lnn_instance) {
        DialogueConfig dconfig;
        memset(&dconfig, 0, sizeof(dconfig));
        dconfig.max_context_length = 20;
        dconfig.enable_context_memory = 1;
        dconfig.response_generation_mode = 1;
        dconfig.confidence_threshold = 0.3f;
        dconfig.language = 0;
        dconfig.dialogue_hidden_size = 128;
        dconfig.dialogue_time_constant = 0.1f;
        dconfig.dialogue_delta_t = 0.05f;
        server->dialogue_processor = dialogue_processor_create(&dconfig);
        if (server->dialogue_processor) {
            dialogue_set_lnn_instance(server->dialogue_processor, server->lnn_instance);
        }
    }
    if (server->dialogue_processor && server->lnn_instance) {
        /* 确保对话处理器绑定了LNN */
        dialogue_set_lnn_instance(server->dialogue_processor, server->lnn_instance);

        /* P1/P4: KG→LNN桥 + 图推理引擎液态推断 */
        {
            void* kg = selflnn_get_knowledge_graph();
            if (kg) {
                knowledge_graph_to_lnn_bridge(kg, server->lnn_instance, 0.15f);
                /* P4: 图推理引擎CfC液态推断注入LNN */
                void* gr = selflnn_get_graph_reasoner();
                if (gr) {
                    int entities[8];
                    float scores[8];
                    graph_reasoner_lnn_infer((GraphReasoner*)gr, 0, 4, entities, scores, 8);
                }
            }
        }

        /* 确保活跃对话上下文存在 */
        if (!server->active_dialogue_context) {
            server->active_dialogue_context = dialogue_context_create(20);
        }

        /* P19修复: 使用dialogue_process_input替代不存在的dialogue_generate_response */
        char* response_text = NULL;
        if (server->dialogue_processor) {
            DialogueResponse* dr = dialogue_process_input(server->dialogue_processor, msg, strlen(msg), NULL);
            if (dr && dr->text) {
                response_text = string_duplicate_nullable(dr->text);
            }
            if (dr) dialogue_response_free(dr);
        }

        if (response_text) {
            /* M-015修复: 将响应拆分为Token，通过WebSocket逐Token推送，
             * 实现流式对话效果。每个UTF-8字符作为一个Token推送。 */
            if (server->ws_push_server) {
                int text_len = (int)strlen(response_text);
                int token_count = 0;
                /* 先计算Token总数（UTF-8字符数） */
                for (int pos = 0; pos < text_len; ) {
                    unsigned char first = (unsigned char)response_text[pos];
                    if (first < 0x80) pos++;
                    else if ((first & 0xE0) == 0xC0) pos += 2;
                    else if ((first & 0xF0) == 0xE0) pos += 3;
                    else if ((first & 0xF8) == 0xF0) pos += 4;
                    else pos++;
                    token_count++;
                }
                /* 逐Token推送 */
                int token_idx = 0;
                for (int pos = 0; pos < text_len; ) {
                    unsigned char first = (unsigned char)response_text[pos];
                    int char_len = 1;
                    if (first < 0x80) char_len = 1;
                    else if ((first & 0xE0) == 0xC0) char_len = 2;
                    else if ((first & 0xF0) == 0xE0) char_len = 3;
                    else if ((first & 0xF8) == 0xF0) char_len = 4;

                    if (pos + char_len > text_len) char_len = text_len - pos;
                    if (char_len < 1) char_len = 1;

                    char token_char[8] = {0};
                    for (int b = 0; b < char_len && b < 7; b++) {
                        token_char[b] = response_text[pos + b];
                    }
                    char escaped_token[32];
                    json_escape_into(escaped_token, sizeof(escaped_token), token_char);

                    char token_json[256];
                    snprintf(token_json, sizeof(token_json),
                        "{\"token_index\":%d,\"token_count\":%d,\"token\":\"%s\"}",
                        token_idx, token_count, escaped_token);
                    ws_push_broadcast(server->ws_push_server, WS_MSG_DIALOGUE_TOKEN, token_json);

                    pos += char_len;
                    token_idx++;
                }
            }

/* 对话输出安全过滤 — 原仅检查输入, 生成响应后无过滤
             * 补充对生成内容的检查, 与多模态对话路径保持一致 */
            if (server->content_filter && response_text[0]) {
                ContentFilterResult filter_result;
                memset(&filter_result, 0, sizeof(ContentFilterResult));
                if (content_filter_check(server->content_filter,
                                        response_text, strlen(response_text),
                                        &filter_result) == 0) {
                    if (filter_result.blocked) {
                        resp->data = string_duplicate(
                            "{\"success\":false,\"reply\":\"回复内容被安全过滤器拦截\","
                            "\"confidence\":0.0,\"safety_filtered\":true}");
                        resp->data_length = strlen(resp->data);
                        resp->status_code = 200;
                        return 0;
                    }
                }
            }

            /* R003注入点5: KG实体标注——在回复中标记已知实体 */
            {
                void* kg_raw = selflnn_get_knowledge_graph();
                if (kg_raw) {
                    KnowledgeGraph* kg = (KnowledgeGraph*)kg_raw;
                    /* 在response_text中查找KG实体 */
                    char kg_buf[512];
                    int kg_pos = 0;
                    size_t max_nc = 0;
                    knowledge_graph_get_stats(kg, &max_nc, NULL, NULL);
                    /* 遍历KG节点，查response_text是否包含节点标签 */
                    if (max_nc > 0 && max_nc < 10000) {
                        KnowledgeGraphNode** all_nodes = (KnowledgeGraphNode**)
                            safe_malloc(max_nc * sizeof(KnowledgeGraphNode*));
                        if (all_nodes) {
                            size_t nc = knowledge_graph_get_all_nodes(kg, all_nodes, max_nc);
                            for (size_t ni = 0; ni < nc && kg_pos < 480; ni++) {
                                if (all_nodes[ni] && all_nodes[ni]->label) {
                                    const char* lbl = all_nodes[ni]->label;
                                    if (strlen(lbl) >= 2 && strstr(response_text, lbl)) {
                                        kg_pos += snprintf(kg_buf + kg_pos,
                                            512 - (size_t)kg_pos, "%s%s",
                                            (kg_pos > 0 ? "," : ""), lbl);
                                    }
                                }
                            }
                            safe_free((void**)&all_nodes);
                        }
                    }
                    if (kg_pos > 0) {
                        /* 追加KG标注到reply */
                        size_t rlen = strlen(response_text);
                        size_t newlen = rlen + kg_pos + 64;
                        char* augmented = (char*)safe_malloc(newlen);
                        if (augmented) {
                            snprintf(augmented, newlen,
                                "%s [KG: %s]", response_text, kg_buf);
                            safe_free((void**)&response_text);
                            response_text = augmented;
                        }
                    }
                }
            }

            /* 发送完整响应 */
            char escaped_reply[4096];
            json_escape_into(escaped_reply, sizeof(escaped_reply), response_text);
            char* j = (char*)safe_malloc(8192);
            if (j) {
                snprintf(j, 8192,
                    "{\"success\":true,\"reply\":\"%s\",\"confidence\":%.4f,\"model\":\"cfc_lnn\",\"tokens_used\":%d}",
                    escaped_reply, (double)0.75, (int)(strlen(response_text) / 3) + 1);
                resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
            }
            return 0;
        }
    }

/* LNN回退路径——生成有意义的状态感知回复，而非模板填充 */
    if (server->lnn_instance) {
        float input_vec[256];
        memset(input_vec, 0, sizeof(input_vec));
        size_t text_len = strlen(msg);
        int dim = 0;
        for (size_t i = 0; i < text_len && i < 200 && dim < 256; i++) {
            input_vec[dim++] = (float)(unsigned char)msg[i] / 255.0f;
        }
        {
            /* P2-005修复: 对话回退路径 —— 对话子系统不可用时明确告知用户
             * 不再使用LNN数值生成描述性文本，避免产生无意义的回复 */
            char reply[512];
            snprintf(reply, sizeof(reply),
                "系统对话模块未就绪，当前仅可使用基础查询功能。"
                "请确认对话引擎已初始化并完成训练后重试。");
            char* j = (char*)safe_malloc(2048);
            if (j) {
                snprintf(j, 2048,
                    "{\"success\":false,\"reply\":\"%s\",\"confidence\":0.0,\"model\":\"unavailable\"}",
                    reply);
                resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
            }
            return 0;
        }
    }

    /* 最终回退：所有子系统不可用 */
    {
        char* j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"success\":false,\"reply\":\"对话系统正在初始化，请稍后再试\",\"confidence\":0.0}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
    }
    return 0;
}

static int handle_api_get_dialogue_send(BackendServer* s, ApiRequestType rt, const char* d, size_t l, ApiResponse* r) {
    return handle_api_post_dialogue_send(s, rt, d, l, r);
}

/* ===== P0-002: 认知/元认知端点 (槽位93) ===== */
static int handle_api_get_metacognition_state(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)data; (void)len;
    char* j = NULL;
    int has_meta = (server->metacognition_system != NULL);
    int has_cog = (server->cognition_system != NULL);
    if (!has_meta && !has_cog) {
        j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"error\":\"元认知系统未初始化\",\"code\":93,\"status\":503}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    char stats_buf[4096];
    memset(stats_buf, 0, sizeof(stats_buf));
    MetacognitionModelState model_state;
    memset(&model_state, 0, sizeof(model_state));
    if (has_meta) {
        metacognition_get_statistics(server->metacognition_system, stats_buf, sizeof(stats_buf));
        metacognition_get_self_model_state(server->metacognition_system, &model_state);
    }
    j = (char*)safe_malloc(8192);
    if (j) {
        snprintf(j, 8192,
            "{\"metacognition\":{"
            "\"has_metacognition\":%s,"
            "\"has_cognition\":%s,"
            "\"statistics\":%s,"
            "\"self_model\":{"
                "\"model_confidence\":%.3f,"
                "\"model_accuracy\":%.3f,"
                "\"update_count\":%zu,"
                "\"last_update_time\":%zu"
            "}}}",
            has_meta ? "true" : "false",
            has_cog ? "true" : "false",
            stats_buf[0] ? stats_buf : "{}",
            has_meta ? model_state.model_confidence : 0.0f,
            has_meta ? model_state.model_accuracy : 0.0f,
            has_meta ? model_state.update_count : (size_t)0,
            has_meta ? model_state.last_update_time : (size_t)0);
        resp->data = j; resp->data_length = strlen(j); resp->status_code = 200;
    }
    return 0;
}

/* ===== P0-002: 元认知反思 (槽位94) ===== */
static int handle_api_post_metacognition_reflect(BackendServer* server,
        ApiRequestType rt, const char* data, size_t len, ApiResponse* resp) {
    (void)rt; (void)data; (void)len;
    char* j = NULL;
    int has_meta = (server->metacognition_system != NULL);
    if (!has_meta) {
        j = (char*)safe_malloc(256);
        if (j) {
            snprintf(j, 256, "{\"error\":\"元认知系统未初始化\",\"code\":94,\"status\":503}");
            resp->data = j; resp->data_length = strlen(j); resp->status_code = 503;
        }
        return 0;
    }
    /* 元认知反思：通过自我认知系统获取当前状态评估 */
    char reflection[4096];
    memset(reflection, 0, sizeof(reflection));
    int reflect_ok = 0;
    if (server->cognition_system) {
        self_cognition_neutral_assessment(server->cognition_system, 0, reflection, sizeof(reflection));
        reflect_ok = (reflection[0] != '\0') ? 0 : -1;
    } else {
        snprintf(reflection, sizeof(reflection), "元认知系统已就绪，等待首次反思周期");
    }
    j = (char*)safe_malloc(6144);
    if (j) {
        snprintf(j, 6144,
            "{\"metacognition_reflection\":{"
            "\"status\":\"%s\","
            "\"has_metacognition\":true,"
            "\"reflection\":\"%s\","
            "\"reflect_result\":%d"
            "}}",
            reflect_ok == 0 ? "success" : "partial",
            reflection[0] ? reflection : "反思已执行",
            reflect_ok);
        resp->data = j; resp->data_length = strlen(j); resp->status_code = reflect_ok == 0 ? 200 : 500;
    }
    return 0;
}

